199 PreservedAnalyses BDCEPass::run(Function &F, FunctionAnalysisManager &AM) {
200   auto &DB = AM.getResult<DemandedBitsAnalysis>(F);
201   if (!bitTrackingDCE(F, DB))
202     return PreservedAnalyses::all();
203 
204   PreservedAnalyses PA;
205   PA.preserveSet<CFGAnalyses>();
206   return PA;
207 }
