349 void Instruction::dropPoisonGeneratingFlags() {
350   switch (getOpcode()) {
351   case Instruction::Add:
352   case Instruction::Sub:
353   case Instruction::Mul:
354   case Instruction::Shl:
355     cast<OverflowingBinaryOperator>(this)->setHasNoUnsignedWrap(false);
356     cast<OverflowingBinaryOperator>(this)->setHasNoSignedWrap(false);
357     break;
358 
359   case Instruction::UDiv:
360   case Instruction::SDiv:
361   case Instruction::AShr:
362   case Instruction::LShr:
363     cast<PossiblyExactOperator>(this)->setIsExact(false);
364     break;
365 
366   case Instruction::Or:
367     cast<PossiblyDisjointInst>(this)->setIsDisjoint(false);
368     break;
369 
370   case Instruction::GetElementPtr:
371     cast<GetElementPtrInst>(this)->setIsInBounds(false);
372     break;
373 
374   case Instruction::ZExt:
375     setNonNeg(false);
376     break;
377   }
378 
379   if (isa<FPMathOperator>(this)) {
380     setHasNoNaNs(false);
381     setHasNoInfs(false);
382   }
383 
384   assert(!hasPoisonGeneratingFlags() && "must be kept in sync");
