531 void Instruction::copyIRFlags(const Value *V, bool IncludeWrapFlags) {
532   // Copy the wrapping flags.
533   if (IncludeWrapFlags && isa<OverflowingBinaryOperator>(this)) {
534     if (auto *OB = dyn_cast<OverflowingBinaryOperator>(V)) {
535       setHasNoSignedWrap(OB->hasNoSignedWrap());
536       setHasNoUnsignedWrap(OB->hasNoUnsignedWrap());
537     }
538   }
539 
540   // Copy the exact flag.
541   if (auto *PE = dyn_cast<PossiblyExactOperator>(V))
542     if (isa<PossiblyExactOperator>(this))
543       setIsExact(PE->isExact());
544 
545   if (auto *SrcPD = dyn_cast<PossiblyDisjointInst>(V))
546     if (auto *DestPD = dyn_cast<PossiblyDisjointInst>(this))
547       DestPD->setIsDisjoint(SrcPD->isDisjoint());
548 
549   // Copy the fast-math flags.
550   if (auto *FP = dyn_cast<FPMathOperator>(V))
551     if (isa<FPMathOperator>(this))
552       copyFastMathFlags(FP->getFastMathFlags());
553 
554   if (auto *SrcGEP = dyn_cast<GetElementPtrInst>(V))
555     if (auto *DestGEP = dyn_cast<GetElementPtrInst>(this))
556       DestGEP->setIsInBounds(SrcGEP->isInBounds() || DestGEP->isInBounds());
557 
558   if (auto *NNI = dyn_cast<PossiblyNonNegInst>(V))
559     if (isa<PossiblyNonNegInst>(this))
560       setNonNeg(NNI->hasNonNeg());
